var minInsertions = function(s) {
    let res = 0;
    let left = 0;
    let i = 0;
    const n = s.length;
    while (i < n) {
        if (s[i] === '(') {
            left++;
            i++;
        } else {
            if (i + 1 < n && s[i + 1] === ')') {
                i += 2;
            } else {
                res++;
                i++;
            }
            if (left === 0) {
                res++;
            } else {
                left--;
            }
        }
    }
    res += left * 2;
    return res;
};
